     1→import 'dotenv/config';
     2→
     3→import multipart from '@fastify/multipart';
     4→import { Logger, ValidationPipe } from '@nestjs/common';
     5→import { NestFactory } from '@nestjs/core';
     6→import {
     7→  FastifyAdapter,
     8→  NestFastifyApplication,
     9→} from '@nestjs/platform-fastify';
    10→import { DocumentBuilder, SwaggerModule } from '@nestjs/swagger';
    11→import * as process from 'node:process';
    12→
    13→import { LoggingInterceptor } from '@/common/interceptors';
    14→import { configureRawBody } from '@/common/config/fastify-raw-body.config';
    15→
    16→import { env } from './env';
    17→import { RootModule } from './root.module';
    18→
    19→process.on('unhandledRejection', (reason) => {
    20→  Logger.error(`Unhandled Rejection reason: ${reason}`, (reason as any)?.stack);
    21→});
    22→
    23→function setupSwagger(app: NestFastifyApplication) {
    24→  const config = new DocumentBuilder()
    25→    .setTitle('LuxFlow API')
    26→    .setDescription('API documentation for LuxFlow')
    27→    .setVersion('0.0.1')
    28→    .addBearerAuth()
    29→    .build();
    30→  const documentFactory = () => SwaggerModule.createDocument(app, config);
    31→
    32→  SwaggerModule.setup(env.SWAGGER_ENDPOINT, app, documentFactory, {
    33→    swaggerOptions: {
    34→      persistAuthorization: true,
    35→    },
    36→  });
    37→}
    38→
    39→function setupHttp(app: NestFastifyApplication) {
    40→  app.useGlobalPipes(
    41→    new ValidationPipe({
    42→      whitelist: true,
    43→      transform: true,
    44→      transformOptions: { enableImplicitConversion: true },
    45→    }),
    46→  );
    47→
    48→  // Apply global interceptors for HTTP request logging
    49→  app.useGlobalInterceptors(new LoggingInterceptor());
    50→
    51→  Logger.log('HTTP request logging enabled', 'API');
    52→}
    53→
    54→function setupCors(app: NestFastifyApplication) {
    55→  app.enableCors({
    56→    origin: env.CORE_ORIGINS,
    57→    methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'],
    58→    credentials: true,
    59→  });
    60→}
    61→
    62→async function bootstrap() {
    63→  const fastifyAdapter = new FastifyAdapter();
    64→
    65→  const app = await NestFactory.create<NestFastifyApplication>(
    66→    RootModule,
    67→    fastifyAdapter,
    68→    {
    69→      snapshot: true,
    70→    },
    71→  );
    72→
    73→  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
    74→  // @ts-expect-error
    75→  await app.register(multipart, {
    76→    attachFieldsToBody: 'keyValues',
    77→    onFile: async (file) => {
    78→      await file.toBuffer();
    79→
    80→      // exclude `fields` property from a result, because it leads to callstack exceed
    81→      // eslint-disable-next-line @typescript-eslint/no-unused-vars
    82→      const { fields, ...rest } = file;
    83→      // @ts-expect-error is ok
    84→      file.value = rest;
    85→    },
    86→    limits: {
    87→      fileSize: 20_971_520,
    88→    },
    89→  });
    90→
    91→  // Configure raw body capture for webhook routes (required for signature verification)
    92→  const fastifyInstance = app.getHttpAdapter().getInstance();
    93→  configureRawBody(fastifyInstance);
    94→
    95→  setupHttp(app);
    96→  setupCors(app);
    97→  setupSwagger(app);
    98→
    99→  await app.listen(env.CORE_PORT, env.CORE_HOST);
   100→}
   101→
   102→bootstrap();
   103→

