     1→import {
     2→  Body,
     3→  Controller,
     4→  Delete,
     5→  Get,
     6→  HttpCode,
     7→  HttpStatus,
     8→  Param,
     9→  Patch,
    10→  Post,
    11→} from '@nestjs/common';
    12→import { ApiExtraModels, ApiTags } from '@nestjs/swagger';
    13→
    14→import { Protected } from '@/modules/auth';
    15→import { UserRole } from '@/db';
    16→import { PaymentsService } from '@/modules/payments';
    17→import { ContextService } from '@/modules/global';
    18→
    19→import { CreatePaymentDto, PaymentResponseDto, UpdatePaymentDto } from './dtos';
    20→import {
    21→  CreatePaymentOpenApi,
    22→  DeletePaymentOpenApi,
    23→  GetPaymentOpenApi,
    24→  GetPaymentsOpenApi,
    25→  UpdatePaymentOpenApi,
    26→} from './payments.openapi';
    27→
    28→@ApiTags('App / Payments')
    29→@ApiExtraModels(PaymentResponseDto)
    30→@Controller()
    31→@Protected([UserRole.Bidder, UserRole.Seller, UserRole.Retailer])
    32→export class PaymentsController {
    33→  constructor(
    34→    private readonly paymentsService: PaymentsService,
    35→    private readonly contextService: ContextService,
    36→  ) {}
    37→
    38→  /**
    39→   * Create a new payment intent.
    40→   * Converts amounts to minor units, validates currency, and supports idempotent creation.
    41→   */
    42→  @Post('/')
    43→  @CreatePaymentOpenApi()
    44→  async createPayment(
    45→    @Body() body: CreatePaymentDto,
    46→  ): Promise<PaymentResponseDto> {
    47→    const userId = this.contextService.context.user.id;
    48→
    49→    // Pass DTO directly to service (no manual field spreading)
    50→    const payment = await this.paymentsService.create(userId, body);
    51→
    52→    return PaymentResponseDto.mapFromEntity(payment);
    53→  }
    54→
    55→  /**
    56→   * List all payments for the current user.
    57→   * Returns payments ordered by creation date (newest first).
    58→   */
    59→  @Get('/')
    60→  @GetPaymentsOpenApi()
    61→  async getPayments(): Promise<PaymentResponseDto[]> {
    62→    const userId = this.contextService.context.user.id;
    63→
    64→    const payments = await this.paymentsService.getMany(userId);
    65→
    66→    return payments.map((payment) => PaymentResponseDto.mapFromEntity(payment));
    67→  }
    68→
    69→  /**
    70→   * Get a specific payment by ID.
    71→   * Only returns payment if it belongs to the current user.
    72→   */
    73→  @Get('/:id')
    74→  @GetPaymentOpenApi()
    75→  async getPayment(@Param('id') id: string): Promise<PaymentResponseDto> {
    76→    const userId = this.contextService.context.user.id;
    77→
    78→    const payment = await this.paymentsService.getOne(userId, id);
    79→
    80→    return PaymentResponseDto.mapFromEntity(payment);
    81→  }
    82→
    83→  /**
    84→   * Update a payment's method or metadata.
    85→   * Only allowed when payment status is CREATED (before provider processing).
    86→   */
    87→  @Patch('/:id')
    88→  @UpdatePaymentOpenApi()
    89→  async updatePayment(
    90→    @Param('id') id: string,
    91→    @Body() body: UpdatePaymentDto,
    92→  ): Promise<PaymentResponseDto> {
    93→    const userId = this.contextService.context.user.id;
    94→
    95→    const payment = await this.paymentsService.update(userId, id, {
    96→      method: body.method,
    97→      metadata: body.metadata,
    98→    });
    99→
   100→    return PaymentResponseDto.mapFromEntity(payment);
   101→  }
   102→
   103→  /**
   104→   * Delete a payment before it's processed.
   105→   * Only allowed for CREATED/PENDING payments without provider reference.
   106→   */
   107→  @Delete('/:id')
   108→  @HttpCode(HttpStatus.NO_CONTENT)
   109→  @DeletePaymentOpenApi()
   110→  async deletePayment(@Param('id') id: string): Promise<void> {
   111→    const userId = this.contextService.context.user.id;
   112→
   113→    await this.paymentsService.delete(userId, id);
   114→  }
   115→}
