    20→import { UN_PROTECT_KEY } from '../decorators';
    21→import { CognitoService } from '../services';
    22→import { AuthenticatedPersonFastifyRequest } from '../types';
    23→import { EMAIL_AUTH_ENABLED } from '@/env';
    24→
    25→function extractBearerToken(header: string | undefined) {
    26→  const [type, token] = header ? header.split(' ') : [];
    27→
    28→  return type === 'Bearer' ? token : null;
    29→}
    30→
    31→@Injectable()
    32→export class AuthGuard implements CanActivate {
    33→  constructor(
    34→    private readonly reflector: Reflector,
    35→    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    36→    private readonly cognitoService: CognitoService,
    37→    private readonly contextService: ContextService,
    38→  ) {}
    39→
    40→  public async canActivate(context: ExecutionContext): Promise<boolean> {
    41→    const isUnProtectedDecoratorSpecified =
    42→      this.reflector.getAllAndOverride<boolean>(UN_PROTECT_KEY, [
    43→        context.getHandler(),
    44→        context.getClass(),
    45→      ]);
    46→
    47→    if (isUnProtectedDecoratorSpecified) {
    48→      return true;
    49→    }
    50→
    51→    const type = context.getType();
    52→
    53→    const requiredUserRoles = this.reflector.getAllAndOverride<UserRole[]>(
    54→      'roles',
    55→      [context.getHandler(), context.getClass()],
    56→    );
    57→
    58→    const requiredPermission = this.reflector.getAllAndOverride<Permission>(
    59→      'permission',
    60→      [context.getHandler(), context.getClass()],
    61→    );
    62→
    63→    if (type === 'http') {
    64→      return this.handleHttp(context, requiredUserRoles, requiredPermission);
    65→    }
    66→
    67→    return false;
    68→  }
    69→
    70→  private async handleHttp(
    71→    context: ExecutionContext,
    72→    userRoles: UserRole[],
    73→    permission: Permission,
    74→  ) {
    75→    const request = context
    76→      .switchToHttp()
    77→      .getRequest<AuthenticatedPersonFastifyRequest>();
    78→    const jwt = extractBearerToken(request.headers.authorization);
    79→
    80→    if (!jwt) {
    81→      throw new UnauthorizedException();
    82→    }
    83→
    84→    let email: string;
    85→
    86→    if (EMAIL_AUTH_ENABLED) {
    87→      email = jwt;
    88→    } else {
    89→      try {
    90→        email = await this.cognitoService.getAccessTokenOwnerEmail(jwt);
    91→      } catch {
    92→        throw new UnauthorizedException();
    93→      }
    94→    }
    95→
    96→    const userRepository = this.txHost.tx.getRepository(UserEntity);
    97→
    98→    const user = await userRepository.findOne({
    99→      where: {
   100→        email,
   101→        status: UserStatus.Active,
   102→      },
   103→    });
   104→
   105→    if (!user) {
   106→      throw new UnauthorizedException();
   107→    }
   108→
   109→    this.contextService.context.user = user;
   110→    this.contextService.context.role = user.selectedRole;
   111→
   112→    if (userRoles?.length && !userRoles.includes(user.selectedRole)) {
   113→      throw new UnauthorizedException();
   114→    }
   115→
   116→    if (user.selectedRole === UserRole.Authenticator) {
   117→      const authenticatorRepository =
   118→        this.txHost.tx.getRepository(AuthenticatorEntity);
   119→      const authenticator = await authenticatorRepository.findOne({
   120→        where: {
   121→          user: { id: user.id },
   122→        },
   123→      });
   124→
   125→      if (!authenticator) {
   126→        throw new UnauthorizedException();
   127→      }
   128→
   129→      this.contextService.context.authenticatorId = authenticator.id;
   130→    }
   131→
   132→    if ([UserRole.Admin, UserRole.SuperAdmin].includes(user.selectedRole)) {
   133→      const adminRepository = this.txHost.tx.getRepository(AdminEntity);
   134→      const admin = await adminRepository.findOne({
   135→        where: {
   136→          user: { id: user.id },
   137→        },
   138→        relations: ['adminRoles'],
   139→      });
   140→
   141→      if (!admin) {
   142→        throw new UnauthorizedException();
   143→      }
   144→
   145→      if (user.selectedRole === UserRole.Admin) {
   146→        const adminPermissions = admin.adminRoles.flatMap(
   147→          (role) => role.permissions,
   148→        );
   149→
   150→        this.contextService.context.permissions = adminPermissions;
   151→      }
   152→
   153→      if (user.selectedRole === UserRole.SuperAdmin) {
   154→        this.contextService.context.permissions = Object.values(Permission);
   155→      }
   156→
   157→      this.contextService.context.admin = admin;
   158→    }
   159→
   160→    if (
   161→      permission &&
   162→      !this.contextService.context.permissions.includes(permission)
   163→    ) {
   164→      throw new UnauthorizedException();
   165→    }
   166→
   167→    request.token = jwt;
   168→    request.user = user;
   169→
   170→    return true;
   171→  }
   172→}
